#include <stdio.h>
#include <string.h>

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        char s[2001];
        scanf("%s", s);
        int n = strlen(s);
        char res[2001] = "";
        int len = 0;
        for (int i = 0; i < n; i++) {
            for (int j = n - 1; j >= i; j--) {
                if ((i + 1) % 2 == 1 && s[i] < s[j]) {
                    res[len++] = s[i];
                    break;
                } else if ((i + 1) % 2 == 0 && s[i] > s[j]) {
                    res[len++] = s[i];
                    break;
                }
            }
        }
        res[len] = '\0';
        printf("%s\n", res);
    }
    return 0;
}

