    cin >> t;
    while (t--) {
        string s;
        cin >> s;
        int n = s.length();
        string res = "";
        for (int i = 0; i < n; i++) {
            for (int j = n - 1; j >= i; j--) {
                if ((i + 1) % 2 == 1 && s[i] < s[j]) {
                    res += s[i];
                    break;
                } else if ((i + 1) % 2 == 0 && s[i] > s[j]) {
                    res += s[i];
                    break;
                }
            }
        }
        cout << res << endl;
    }
    return 0;
}

