import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int t = sc.nextInt();
        while (t-- > 0) {
            String s = sc.next();
            int n = s.length();
            StringBuilder res = new StringBuilder();
            for (int i = 0; i < n; i++) {
                for (int j = n - 1; j >= i; j--) {
                    if ((i + 1) % 2 == 1 && s.charAt(i) < s.charAt(j)) {
                        res.append(s.charAt(i));
                        break;
                    } else if ((i + 1) % 2 == 0 && s.charAt(i) > s.charAt(j)) {
                        res.append(s.charAt(i));
                        break;
                    }
                }
            }
            System.out.println(res.toString());
        }
    }
}

